import json
from browser_harness.helpers import js, page_info

buttons = js('''
Array.from(document.querySelectorAll('button, [role="button"], [role="link"], a, input, textarea, select'))
    .map(el => ({
        tag: el.tagName,
        type: el.type || null,
        id: el.id || null,
        name: el.name || null,
        class: el.className || null,
        text: el.innerText?.trim() || el.value || null,
        placeholder: el.placeholder || null,
        href: el.href || null,
        aria_label: el.getAttribute('aria-label') || null,
        data_testid: el.getAttribute('data-testid') || null,
        visible: el.offsetParent !== null,
        disabled: el.disabled || false,
        xpath: (function() {
            if (el.id) return '//*[@id="' + el.id + '"]';
            let ix = 0;
            let siblings = el.parentNode.childNodes;
            for (let i = 0; i < siblings.length; i++) {
                let sibling = siblings[i];
                if (sibling === el) {
                    let parentPath = el.parentNode === document.body ? '/html/body' : '';
                    return parentPath + '/' + el.tagName.toLowerCase() + '[' + (ix + 1) + ']';
                }
                if (sibling.nodeType === 1 && sibling.tagName === el.tagName) ix++;
            }
        })()
    }))
''')

result = {
    'url': page_info()['url'],
    'title': page_info()['title'],
    'buttons': [b for b in buttons if b['tag'] in ['BUTTON', 'A'] or 'button' in str(b.get('aria_label', '')).lower()],
    'inputs': [b for b in buttons if b['tag'] in ['INPUT', 'TEXTAREA', 'SELECT']],
    'links': [b for b in buttons if b['tag'] == 'A' and b['href'] and b['href'] != '#'],
    'all': buttons,
    'total': len(buttons)
}

with open('/app/page_elements.json', 'w', encoding='utf-8') as f:
    json.dump(result, f, indent=2, ensure_ascii=False)

print(f'✅ URL: {result["url"]}')
print(f'✅ Найдено элементов: {result["total"]}')
print(f'   Кнопок: {len(result["buttons"])}')
print(f'   Полей: {len(result["inputs"])}')
print(f'   Ссылок: {len(result["links"])}')
print('\n📄 Результат: page_elements.json')

if result['buttons']:
    print('\n📌 Примеры кнопок:')
    for b in result['buttons'][:5]:
        print(f'   - {b["text"] or b["aria_label"] or b["id"]} ({b["tag"]})')

if result['inputs']:
    print('\n📝 Примеры полей:')
    for b in result['inputs'][:5]:
        print(f'   - {b["name"] or b["id"] or b["placeholder"]} ({b["type"]})')
